import pandas as pddef limpiar_precio(df):    """    Limpia la columna 'price' del DataFrame y la convierte a tipo numérico.    Parámetros:        df (pd.DataFrame): DataFrame cargado desde el CSV de Airbnb.    Retorna:        pd.DataFrame: El mismo DataFrame con la columna 'price' en        formato numérico (float) y sin filas con precio inválido.    """    df = df.copy()    df['price'] = df['price'].str.replace('$', '', regex=False)    df['price'] = df['price'].str.replace(',', '', regex=False)    df['price'] = pd.to_numeric(df['price'], errors='coerce')    df = df.dropna(subset=['price'])    return dfdef filtrar_datos(dataframe):    """    Filtra el dataframe dejando solo las columnas necesarias para el análisis.    (Bloque 3 del diagrama de flujo)        Parámetros    ---------    dataframe: DataFrame        Retorna    -------    DataFrame    El mismo DataFrame pero únicamente con las columnas que necesitamos.    Éstas estan delineadas en columnas_relevantes.     """    if dataframe is None or dataframe.empty:        return None    columnas_relevantes = [        'id', 'name', 'host_id', 'neighbourhood',         'latitude', 'longitude', 'room_type',         'price', 'minimum_nights', 'availability_365',         'number_of_reviews', 'review_scores_rating'    ]        columnas_a_retener = [col for col in columnas_relevantes if col in dataframe.columns]        df_filtrado = dataframe[columnas_a_retener].copy()    print(f"Procesamiento: Dataset filtrado a {len(columnas_a_retener)} columnas clave.")    return df_filtradodef filtrado_por_barrio(preferencia_del_usuario, dataframe_filtrado):    """    Crea un nuevo dataframe (a partir de la ya filtrada) que sea solo de    los alojamientos pertenecientes al barrio elegido por el usuario.        Parámetros    ----------    preferencia_del_usuario: str    Barrio preferido por el usuario.        dataframe_filtrado: DataFrame    DataFrame devuelto por la función filtrar_datos.        Retorna    -------    DataFrame    Un DataFrame acotado con únicamente las opciones de alojamiento en el abrrio elegido por el usuario.    """    if dataframe_filtrado is None or dataframe_filtrado.empty:        return None                barrio_elegido = preferencia_del_usuario.get('barrio')        df_barrio = dataframe_filtrado[        dataframe_filtrado['neighbourhood'].str.lower() == barrio_elegido.lower()    ].copy()        print(f"Procesamiento: Se encontraron {len(df_barrio)} alojamientos en el barrio '{barrio_elegido}'.")    return df_barrio